CREATE TABLE IF NOT EXISTS "public"."tblRoles" (
    "RoleID" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "RoleName" TEXT NOT NULL UNIQUE
);
-- statement-break
CREATE TABLE IF NOT EXISTS "public"."tblPermissions" (
    "PermID" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "PermName" TEXT NOT NULL UNIQUE
);
-- statement-break
CREATE TABLE IF NOT EXISTS "public"."tblRolePermissions" (
    "RoleID" INTEGER NOT NULL REFERENCES "public"."tblRoles" ("RoleID") ON DELETE CASCADE,
    "PermID" INTEGER NOT NULL REFERENCES "public"."tblPermissions" ("PermID") ON DELETE CASCADE,
    PRIMARY KEY ("RoleID", "PermID")
);
-- statement-break
CREATE TABLE IF NOT EXISTS "public"."tblUserRoles" (
    "UserRoleID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "username" TEXT NULL,
    "Idno" TEXT NULL,
    "RoleID" INTEGER NOT NULL REFERENCES "public"."tblRoles" ("RoleID") ON DELETE CASCADE,
    "AssignedAt" TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT "chk_tblUserRoles_identity" CHECK (num_nonnulls("username", "Idno") = 1)
);
-- statement-break
CREATE UNIQUE INDEX IF NOT EXISTS "idx_tblUserRoles_username_role"
    ON "public"."tblUserRoles" ("username", "RoleID")
    WHERE "username" IS NOT NULL;
-- statement-break
CREATE UNIQUE INDEX IF NOT EXISTS "idx_tblUserRoles_idno_role"
    ON "public"."tblUserRoles" ("Idno", "RoleID")
    WHERE "Idno" IS NOT NULL;
-- statement-break
CREATE INDEX IF NOT EXISTS "idx_tblRolePermissions_roleid"
    ON "public"."tblRolePermissions" ("RoleID");
-- statement-break
CREATE INDEX IF NOT EXISTS "idx_tblRolePermissions_permid"
    ON "public"."tblRolePermissions" ("PermID");
-- statement-break
INSERT INTO "public"."tblRoles" ("RoleName")
VALUES
